#include <stdio.h>
#include <stdlib.h>

int main(int argc, char *argv[]) {
    if (argc != 2) {
        printf("Usage: %s filename\n", argv[0]);
        return 1;
    }
    
    // Construct the full path to the file
    const char* directory = "/etc/myapp/configs/";
    size_t dirLen = strlen(directory);
    size_t argLen = strlen(argv[1]);
    char* filename = (char*)malloc(dirLen + argLen + 1);
    
    // Copy the directory and file name into the new string
    memcpy(filename, directory, dirLen);
    memcpy(filename + dirLen, argv[1], argLen + 1);
    
    FILE* file = fopen(filename, "r");
    
    if (file == NULL) {
        printf("Failed to open the file\n");
        return 2;
    }
    
    char buffer[256]; // Buffer for reading file content
    
    while (fgets(buffer, sizeof(buffer), file)) {
        printf("%s", buffer);
    }
    
    fclose(file);
    free(filename);
    return 0;
}